CODE_EXAMPLE:
class OrderProcessor {
    // High-level entry point at top
    public void processOrder(Order order) {
        validate(order);
        save(order);
    }

    private void validate(Order order) {
        if (order.getTotal() <= 0) throw new IllegalArgumentException("Invalid total");
    }

    // Low-level helpers below
    private void save(Order order) { db.insert(order); }
}

UNIT_TEST_EXAMPLE:
@Test
public void processOrder_validatesBeforeSaving() {
    TestDatabase db = new TestDatabase();
    OrderProcessor processor = new OrderProcessor(db);
    assertThrows(IllegalArgumentException.class,
            () -> processor.processOrder(new Order(-1)));
    assertEquals(0, db.getSaveCount());
}
